/**
 * Menu Module Types
 *
 * Type definitions for the Menu module including:
 * - Menu, Category, Product DTOs
 * - Variant and Modifier types
 * - Theme and Allergen types
 * - Event payloads and hook contexts
 *
 * @module modules/menu/types
 *
 * @example
 * ```typescript
 * import type {
 *   Menu,
 *   Category,
 *   Product,
 *   CreateMenuRequest,
 * } from '@/modules/menu/menu.types';
 *
 * async function createMenu(data: CreateMenuRequest): Promise<Menu> { ... }
 * ```
 */

import type { Decimal } from '@prisma/client/runtime/library';

// -----------------------------------------------------------------------------
// Base Types (from Prisma)
// -----------------------------------------------------------------------------

/**
 * Menu settings JSON structure
 */
export interface MenuSettings {
  /** Show product images */
  showImages?: boolean;
  /** Show product prices */
  showPrices?: boolean;
  /** Show product descriptions */
  showDescriptions?: boolean;
  /** Show allergen information */
  showAllergens?: boolean;
  /** Show nutrition information */
  showNutritionInfo?: boolean;
  /** Enable cart/ordering */
  enableOrdering?: boolean;
  /** Custom footer text */
  footerText?: string;
  /** Social media links */
  socialLinks?: Record<string, string>;
}

/**
 * Theme settings JSON structure
 */
export interface ThemeSettings {
  /** Border radius in pixels */
  borderRadius?: number;
  /** Card shadow style */
  cardShadow?: 'none' | 'sm' | 'md' | 'lg';
  /** Header style */
  headerStyle?: 'fixed' | 'sticky' | 'static';
  /** Category layout */
  categoryLayout?: 'grid' | 'list' | 'horizontal';
  /** Product card style */
  productCardStyle?: 'minimal' | 'detailed' | 'image-focused';
  /** Animation enabled */
  enableAnimations?: boolean;
  /** Custom CSS variables */
  cssVariables?: Record<string, string>;
}

// -----------------------------------------------------------------------------
// Menu Types
// -----------------------------------------------------------------------------

/**
 * Menu entity
 */
export interface Menu {
  /** Menu ID */
  id: string;
  /** Organization ID (tenant) */
  organizationId: string;
  /** Branch ID (optional) */
  branchId: string | null;
  /** Menu name */
  name: string;
  /** URL-friendly slug */
  slug: string;
  /** Menu description */
  description: string | null;
  /** Published status */
  isPublished: boolean;
  /** Publish timestamp */
  publishedAt: Date | null;
  /** Default menu flag */
  isDefault: boolean;
  /** Theme ID */
  themeId: string | null;
  /** Menu settings */
  settings: MenuSettings;
  /** Sort order */
  sortOrder: number;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
  /** Soft delete timestamp */
  deletedAt: Date | null;
}

/**
 * Menu with relations
 */
export interface MenuWithRelations extends Menu {
  /** Related theme */
  theme?: Theme | null;
  /** Categories in this menu */
  categories?: Category[];
  /** QR codes for this menu */
  qrCodes?: QRCodeRef[];
}

/**
 * Create menu request
 */
export interface CreateMenuRequest {
  /** Menu name */
  name: string;
  /** URL-friendly slug (auto-generated if not provided) */
  slug?: string;
  /** Menu description */
  description?: string;
  /** Branch ID (optional) */
  branchId?: string;
  /** Theme ID (optional) */
  themeId?: string;
  /** Set as default menu */
  isDefault?: boolean;
  /** Menu settings */
  settings?: MenuSettings;
  /** Sort order */
  sortOrder?: number;
}

/**
 * Update menu request
 */
export interface UpdateMenuRequest {
  /** Menu name */
  name?: string;
  /** URL-friendly slug */
  slug?: string;
  /** Menu description */
  description?: string | null;
  /** Branch ID */
  branchId?: string | null;
  /** Theme ID */
  themeId?: string | null;
  /** Set as default menu */
  isDefault?: boolean;
  /** Menu settings */
  settings?: MenuSettings;
  /** Sort order */
  sortOrder?: number;
}

/**
 * Publish menu request
 */
export interface PublishMenuRequest {
  /** Generate QR code on publish */
  generateQrCode?: boolean;
}

/**
 * Menu list query parameters
 */
export interface ListMenusQuery {
  /** Filter by published status */
  isPublished?: boolean;
  /** Filter by branch ID */
  branchId?: string;
  /** Search by name */
  search?: string;
  /** Page number */
  page?: number;
  /** Items per page */
  perPage?: number;
  /** Sort field */
  sortBy?: 'name' | 'createdAt' | 'updatedAt' | 'sortOrder';
  /** Sort direction */
  sortOrder?: 'asc' | 'desc';
}

// -----------------------------------------------------------------------------
// Category Types
// -----------------------------------------------------------------------------

/**
 * Category entity
 */
export interface Category {
  /** Category ID */
  id: string;
  /** Organization ID (tenant) */
  organizationId: string;
  /** Menu ID */
  menuId: string;
  /** Parent category ID (for nesting) */
  parentId: string | null;
  /** Category name */
  name: string;
  /** URL-friendly slug */
  slug: string;
  /** Category description */
  description: string | null;
  /** Category image URL */
  image: string | null;
  /** Active status */
  isActive: boolean;
  /** Sort order */
  sortOrder: number;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
  /** Soft delete timestamp */
  deletedAt: Date | null;
}

/**
 * Category with relations
 */
export interface CategoryWithRelations extends Category {
  /** Parent category */
  parent?: Category | null;
  /** Child categories */
  children?: Category[];
  /** Products in this category */
  products?: Product[];
}

/**
 * Create category request
 */
export interface CreateCategoryRequest {
  /** Menu ID */
  menuId: string;
  /** Parent category ID (for nesting) */
  parentId?: string;
  /** Category name */
  name: string;
  /** URL-friendly slug (auto-generated if not provided) */
  slug?: string;
  /** Category description */
  description?: string;
  /** Category image URL */
  image?: string;
  /** Active status */
  isActive?: boolean;
  /** Sort order */
  sortOrder?: number;
}

/**
 * Update category request
 */
export interface UpdateCategoryRequest {
  /** Parent category ID */
  parentId?: string | null;
  /** Category name */
  name?: string;
  /** URL-friendly slug */
  slug?: string;
  /** Category description */
  description?: string | null;
  /** Category image URL */
  image?: string | null;
  /** Active status */
  isActive?: boolean;
  /** Sort order */
  sortOrder?: number;
}

/**
 * Reorder categories request
 */
export interface ReorderCategoriesRequest {
  /** Menu ID */
  menuId: string;
  /** Category ID to sort order mapping */
  items: Array<{
    /** Category ID */
    id: string;
    /** New sort order */
    sortOrder: number;
  }>;
}

/**
 * Category list query parameters
 */
export interface ListCategoriesQuery {
  /** Filter by menu ID */
  menuId?: string;
  /** Filter by parent ID (null for root categories) */
  parentId?: string | null;
  /** Filter by active status */
  isActive?: boolean;
  /** Include products */
  includeProducts?: boolean;
  /** Search by name */
  search?: string;
  /** Page number */
  page?: number;
  /** Items per page */
  perPage?: number;
}

// -----------------------------------------------------------------------------
// Product Types
// -----------------------------------------------------------------------------

/**
 * Product entity
 */
export interface Product {
  /** Product ID */
  id: string;
  /** Organization ID (tenant) */
  organizationId: string;
  /** Category ID */
  categoryId: string;
  /** Product name */
  name: string;
  /** URL-friendly slug */
  slug: string;
  /** Full description */
  description: string | null;
  /** Short description (max 100 chars) */
  shortDescription: string | null;
  /** Base price */
  basePrice: Decimal | string | number;
  /** Currency code */
  currency: string;
  /** Main product image URL */
  image: string | null;
  /** Gallery image URLs */
  gallery: string[];
  /** Active status */
  isActive: boolean;
  /** Availability status */
  isAvailable: boolean;
  /** Featured product flag */
  isFeatured: boolean;
  /** Chef recommended flag */
  isChefRecommended: boolean;
  /** Preparation time in minutes */
  preparationTime: number | null;
  /** Calories */
  calories: number | null;
  /** Spicy level (1-5) */
  spicyLevel: number | null;
  /** Product tags */
  tags: string[];
  /** Sort order */
  sortOrder: number;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
  /** Soft delete timestamp */
  deletedAt: Date | null;
}

/**
 * Product with relations
 */
export interface ProductWithRelations extends Product {
  /** Category */
  category?: Category;
  /** Product variants */
  variants?: ProductVariant[];
  /** Product modifiers */
  modifiers?: ProductModifier[];
  /** Allergen information */
  allergens?: AllergenWithPivot[];
  /** Nutrition information */
  nutritionInfo?: NutritionInfo | null;
}

/**
 * Create product request
 */
export interface CreateProductRequest {
  /** Category ID */
  categoryId: string;
  /** Product name */
  name: string;
  /** URL-friendly slug (auto-generated if not provided) */
  slug?: string;
  /** Full description */
  description?: string;
  /** Short description */
  shortDescription?: string;
  /** Base price */
  basePrice: number | string;
  /** Currency code */
  currency?: string;
  /** Main product image URL */
  image?: string;
  /** Gallery image URLs */
  gallery?: string[];
  /** Active status */
  isActive?: boolean;
  /** Availability status */
  isAvailable?: boolean;
  /** Featured product flag */
  isFeatured?: boolean;
  /** Chef recommended flag */
  isChefRecommended?: boolean;
  /** Preparation time in minutes */
  preparationTime?: number;
  /** Calories */
  calories?: number;
  /** Spicy level (1-5) */
  spicyLevel?: number;
  /** Product tags */
  tags?: string[];
  /** Sort order */
  sortOrder?: number;
  /** Allergen IDs */
  allergenIds?: string[];
  /** Variants to create */
  variants?: CreateVariantRequest[];
  /** Modifiers to create */
  modifiers?: CreateModifierRequest[];
  /** Nutrition information */
  nutritionInfo?: CreateNutritionInfoRequest;
}

/**
 * Update product request
 */
export interface UpdateProductRequest {
  /** Category ID */
  categoryId?: string;
  /** Product name */
  name?: string;
  /** URL-friendly slug */
  slug?: string;
  /** Full description */
  description?: string | null;
  /** Short description */
  shortDescription?: string | null;
  /** Base price */
  basePrice?: number | string;
  /** Currency code */
  currency?: string;
  /** Main product image URL */
  image?: string | null;
  /** Gallery image URLs */
  gallery?: string[];
  /** Active status */
  isActive?: boolean;
  /** Availability status */
  isAvailable?: boolean;
  /** Featured product flag */
  isFeatured?: boolean;
  /** Chef recommended flag */
  isChefRecommended?: boolean;
  /** Preparation time in minutes */
  preparationTime?: number | null;
  /** Calories */
  calories?: number | null;
  /** Spicy level (1-5) */
  spicyLevel?: number | null;
  /** Product tags */
  tags?: string[];
  /** Sort order */
  sortOrder?: number;
  /** Allergen IDs */
  allergenIds?: string[];
}

/**
 * Update product availability request
 */
export interface UpdateAvailabilityRequest {
  /** Availability status */
  isAvailable: boolean;
}

/**
 * Product list query parameters
 */
export interface ListProductsQuery {
  /** Filter by category ID */
  categoryId?: string;
  /** Filter by menu ID */
  menuId?: string;
  /** Filter by active status */
  isActive?: boolean;
  /** Filter by availability */
  isAvailable?: boolean;
  /** Filter by featured */
  isFeatured?: boolean;
  /** Filter by allergen ID */
  allergenId?: string;
  /** Search by name */
  search?: string;
  /** Filter by tags */
  tags?: string[];
  /** Include relations */
  include?: Array<'category' | 'variants' | 'modifiers' | 'allergens' | 'nutritionInfo'>;
  /** Page number */
  page?: number;
  /** Items per page */
  perPage?: number;
  /** Sort field */
  sortBy?: 'name' | 'basePrice' | 'createdAt' | 'sortOrder';
  /** Sort direction */
  sortOrder?: 'asc' | 'desc';
}

// -----------------------------------------------------------------------------
// Variant Types
// -----------------------------------------------------------------------------

/**
 * Product variant entity
 */
export interface ProductVariant {
  /** Variant ID */
  id: string;
  /** Product ID */
  productId: string;
  /** Variant name (e.g., "Small", "Medium", "Large") */
  name: string;
  /** Variant price */
  price: Decimal | string | number;
  /** Default variant flag */
  isDefault: boolean;
  /** Availability status */
  isAvailable: boolean;
  /** Sort order */
  sortOrder: number;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
}

/**
 * Create variant request
 */
export interface CreateVariantRequest {
  /** Product ID (optional if nested in product creation) */
  productId?: string;
  /** Variant name */
  name: string;
  /** Variant price */
  price: number | string;
  /** Default variant flag */
  isDefault?: boolean;
  /** Availability status */
  isAvailable?: boolean;
  /** Sort order */
  sortOrder?: number;
}

/**
 * Update variant request
 */
export interface UpdateVariantRequest {
  /** Variant name */
  name?: string;
  /** Variant price */
  price?: number | string;
  /** Default variant flag */
  isDefault?: boolean;
  /** Availability status */
  isAvailable?: boolean;
  /** Sort order */
  sortOrder?: number;
}

// -----------------------------------------------------------------------------
// Modifier Types
// -----------------------------------------------------------------------------

/**
 * Product modifier entity
 */
export interface ProductModifier {
  /** Modifier ID */
  id: string;
  /** Product ID */
  productId: string;
  /** Modifier name (e.g., "Extra Cheese", "No Onions") */
  name: string;
  /** Additional price */
  price: Decimal | string | number;
  /** Default selected flag */
  isDefault: boolean;
  /** Required modifier flag */
  isRequired: boolean;
  /** Maximum quantity allowed */
  maxQuantity: number;
  /** Sort order */
  sortOrder: number;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
}

/**
 * Create modifier request
 */
export interface CreateModifierRequest {
  /** Product ID (optional if nested in product creation) */
  productId?: string;
  /** Modifier name */
  name: string;
  /** Additional price */
  price: number | string;
  /** Default selected flag */
  isDefault?: boolean;
  /** Required modifier flag */
  isRequired?: boolean;
  /** Maximum quantity allowed */
  maxQuantity?: number;
  /** Sort order */
  sortOrder?: number;
}

/**
 * Update modifier request
 */
export interface UpdateModifierRequest {
  /** Modifier name */
  name?: string;
  /** Additional price */
  price?: number | string;
  /** Default selected flag */
  isDefault?: boolean;
  /** Required modifier flag */
  isRequired?: boolean;
  /** Maximum quantity allowed */
  maxQuantity?: number;
  /** Sort order */
  sortOrder?: number;
}

// -----------------------------------------------------------------------------
// Allergen Types
// -----------------------------------------------------------------------------

/**
 * Allergen entity (platform-level, not tenant-scoped)
 */
export interface Allergen {
  /** Allergen ID */
  id: string;
  /** Allergen code (e.g., "gluten", "dairy") */
  code: string;
  /** Allergen name */
  name: string;
  /** Icon identifier */
  icon: string | null;
  /** Allergen description */
  description: string | null;
}

/**
 * Allergen with product pivot data
 */
export interface AllergenWithPivot extends Allergen {
  /** Pivot table data */
  pivot?: {
    productId: string;
    allergenId: string;
  };
}

// -----------------------------------------------------------------------------
// Nutrition Info Types
// -----------------------------------------------------------------------------

/**
 * Nutrition info entity
 */
export interface NutritionInfo {
  /** Nutrition info ID */
  id: string;
  /** Product ID */
  productId: string;
  /** Calories */
  calories: number | null;
  /** Protein in grams */
  protein: Decimal | string | number | null;
  /** Carbohydrates in grams */
  carbohydrates: Decimal | string | number | null;
  /** Fat in grams */
  fat: Decimal | string | number | null;
  /** Fiber in grams */
  fiber: Decimal | string | number | null;
  /** Sodium in mg */
  sodium: Decimal | string | number | null;
  /** Sugar in grams */
  sugar: Decimal | string | number | null;
  /** Serving size */
  servingSize: string | null;
  /** Serving unit */
  servingUnit: string | null;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
}

/**
 * Create nutrition info request
 */
export interface CreateNutritionInfoRequest {
  /** Calories */
  calories?: number;
  /** Protein in grams */
  protein?: number;
  /** Carbohydrates in grams */
  carbohydrates?: number;
  /** Fat in grams */
  fat?: number;
  /** Fiber in grams */
  fiber?: number;
  /** Sodium in mg */
  sodium?: number;
  /** Sugar in grams */
  sugar?: number;
  /** Serving size */
  servingSize?: string;
  /** Serving unit */
  servingUnit?: string;
}

/**
 * Update nutrition info request
 */
export interface UpdateNutritionInfoRequest extends CreateNutritionInfoRequest {}

// -----------------------------------------------------------------------------
// Theme Types
// -----------------------------------------------------------------------------

/**
 * Theme entity
 */
export interface Theme {
  /** Theme ID */
  id: string;
  /** Organization ID (tenant) */
  organizationId: string;
  /** Theme name */
  name: string;
  /** URL-friendly slug */
  slug: string;
  /** Theme description */
  description: string | null;
  /** Primary color (hex) */
  primaryColor: string;
  /** Secondary color (hex) */
  secondaryColor: string;
  /** Background color (hex) */
  backgroundColor: string;
  /** Text color (hex) */
  textColor: string;
  /** Font family */
  fontFamily: string;
  /** Logo position */
  logoPosition: string;
  /** Custom CSS */
  customCss: string | null;
  /** Theme settings */
  settings: ThemeSettings;
  /** Default theme flag */
  isDefault: boolean;
  /** Active status */
  isActive: boolean;
  /** Creation timestamp */
  createdAt: Date;
  /** Last update timestamp */
  updatedAt: Date;
  /** Soft delete timestamp */
  deletedAt: Date | null;
}

/**
 * Create theme request
 */
export interface CreateThemeRequest {
  /** Theme name */
  name: string;
  /** URL-friendly slug (auto-generated if not provided) */
  slug?: string;
  /** Theme description */
  description?: string;
  /** Primary color (hex) */
  primaryColor?: string;
  /** Secondary color (hex) */
  secondaryColor?: string;
  /** Background color (hex) */
  backgroundColor?: string;
  /** Text color (hex) */
  textColor?: string;
  /** Font family */
  fontFamily?: string;
  /** Logo position */
  logoPosition?: string;
  /** Custom CSS */
  customCss?: string;
  /** Theme settings */
  settings?: ThemeSettings;
  /** Default theme flag */
  isDefault?: boolean;
  /** Active status */
  isActive?: boolean;
}

/**
 * Update theme request
 */
export interface UpdateThemeRequest {
  /** Theme name */
  name?: string;
  /** URL-friendly slug */
  slug?: string;
  /** Theme description */
  description?: string | null;
  /** Primary color (hex) */
  primaryColor?: string;
  /** Secondary color (hex) */
  secondaryColor?: string;
  /** Background color (hex) */
  backgroundColor?: string;
  /** Text color (hex) */
  textColor?: string;
  /** Font family */
  fontFamily?: string;
  /** Logo position */
  logoPosition?: string;
  /** Custom CSS */
  customCss?: string | null;
  /** Theme settings */
  settings?: ThemeSettings;
  /** Default theme flag */
  isDefault?: boolean;
  /** Active status */
  isActive?: boolean;
}

/**
 * Theme list query parameters
 */
export interface ListThemesQuery {
  /** Filter by active status */
  isActive?: boolean;
  /** Search by name */
  search?: string;
  /** Page number */
  page?: number;
  /** Items per page */
  perPage?: number;
}

// -----------------------------------------------------------------------------
// QR Code Reference (from order module)
// -----------------------------------------------------------------------------

/**
 * QR Code reference type (defined in order module)
 */
export interface QRCodeRef {
  /** QR Code ID */
  id: string;
  /** Menu ID */
  menuId: string;
  /** QR Code URL */
  url: string;
  /** QR Code image URL */
  imageUrl: string | null;
}

// -----------------------------------------------------------------------------
// Event Payloads
// -----------------------------------------------------------------------------

/**
 * Menu created event payload
 */
export interface MenuCreatedEvent {
  /** Menu ID */
  menuId: string;
  /** Organization ID */
  organizationId: string;
  /** Menu name */
  name: string;
  /** Timestamp */
  timestamp: string;
}

/**
 * Menu updated event payload
 */
export interface MenuUpdatedEvent {
  /** Menu ID */
  menuId: string;
  /** Organization ID */
  organizationId: string;
  /** Changed fields */
  changes: Partial<Menu>;
  /** Timestamp */
  timestamp: string;
}

/**
 * Menu deleted event payload
 */
export interface MenuDeletedEvent {
  /** Menu ID */
  menuId: string;
  /** Organization ID */
  organizationId: string;
  /** Timestamp */
  timestamp: string;
}

/**
 * Menu published event payload
 */
export interface MenuPublishedEvent {
  /** Menu ID */
  menuId: string;
  /** Organization ID */
  organizationId: string;
  /** Publish timestamp */
  publishedAt: string;
  /** QR Code generated */
  qrCodeGenerated: boolean;
  /** Timestamp */
  timestamp: string;
}

/**
 * Product created event payload
 */
export interface ProductCreatedEvent {
  /** Product ID */
  productId: string;
  /** Organization ID */
  organizationId: string;
  /** Category ID */
  categoryId: string;
  /** Product name */
  name: string;
  /** Timestamp */
  timestamp: string;
}

/**
 * Product availability changed event payload
 */
export interface ProductAvailabilityChangedEvent {
  /** Product ID */
  productId: string;
  /** Organization ID */
  organizationId: string;
  /** Previous availability */
  previousAvailability: boolean;
  /** New availability */
  newAvailability: boolean;
  /** Timestamp */
  timestamp: string;
}

/**
 * Category reordered event payload
 */
export interface CategoryReorderedEvent {
  /** Menu ID */
  menuId: string;
  /** Organization ID */
  organizationId: string;
  /** Reordered category IDs with new positions */
  items: Array<{ id: string; sortOrder: number }>;
  /** Timestamp */
  timestamp: string;
}

// -----------------------------------------------------------------------------
// Hook Contexts
// -----------------------------------------------------------------------------

/**
 * Before menu create hook context
 */
export interface BeforeMenuCreateContext {
  /** Create request data */
  data: CreateMenuRequest;
  /** Organization ID */
  organizationId: string;
}

/**
 * After menu create hook context
 */
export interface AfterMenuCreateContext {
  /** Created menu */
  menu: Menu;
  /** Organization ID */
  organizationId: string;
}

/**
 * Before menu publish hook context
 */
export interface BeforeMenuPublishContext {
  /** Menu to publish */
  menu: Menu;
  /** Publish options */
  options: PublishMenuRequest;
}

/**
 * After menu publish hook context
 */
export interface AfterMenuPublishContext {
  /** Published menu */
  menu: Menu;
  /** QR code URL if generated */
  qrCodeUrl?: string;
}

/**
 * Before product create hook context
 */
export interface BeforeProductCreateContext {
  /** Create request data */
  data: CreateProductRequest;
  /** Organization ID */
  organizationId: string;
  /** Category */
  category: Category;
}

/**
 * After product create hook context
 */
export interface AfterProductCreateContext {
  /** Created product */
  product: ProductWithRelations;
  /** Organization ID */
  organizationId: string;
}

// -----------------------------------------------------------------------------
// Module Settings Types
// -----------------------------------------------------------------------------

/**
 * Menu module settings
 */
export interface MenuModuleSettings {
  /** Default currency for prices */
  defaultCurrency: string;
  /** Enable product variants */
  enableVariants: boolean;
  /** Enable product modifiers */
  enableModifiers: boolean;
  /** Enable nutrition information */
  enableNutritionInfo: boolean;
  /** Enable allergen information */
  enableAllergens: boolean;
  /** Maximum categories per menu */
  maxCategoriesPerMenu: number;
  /** Maximum products per category */
  maxProductsPerCategory: number;
  /** Maximum variants per product */
  maxVariantsPerProduct: number;
  /** Maximum modifiers per product */
  maxModifiersPerProduct: number;
  /** Maximum images per product */
  maxImagesPerProduct: number;
  /** Maximum image size in KB */
  imageMaxSizeKb: number;
  /** Auto-generate slugs */
  slugAutoGenerate: boolean;
}

// -----------------------------------------------------------------------------
// Response Types
// -----------------------------------------------------------------------------

/**
 * Menu response (API)
 */
export interface MenuResponse extends Menu {
  /** Category count */
  categoryCount?: number;
  /** Product count */
  productCount?: number;
  /** Theme info */
  theme?: Theme | null;
}

/**
 * Category tree node
 */
export interface CategoryTreeNode extends Category {
  /** Child categories */
  children: CategoryTreeNode[];
  /** Products in this category */
  products?: Product[];
}

/**
 * Public menu response (customer-facing)
 */
export interface PublicMenuResponse {
  /** Menu info */
  menu: Pick<Menu, 'id' | 'name' | 'slug' | 'description' | 'settings'>;
  /** Organization info */
  organization: {
    name: string;
    logo?: string;
  };
  /** Theme */
  theme: Theme | null;
  /** Category tree with products */
  categories: CategoryTreeNode[];
  /** Featured products */
  featuredProducts: Product[];
}
